    "example_question_sqls": [
      {
        "id": "01f11194cb541456845f48fd8b493012",
        "question": [
          "Monthly trend of the main KPIs for the past 13 months"
        ],
        "sql": [
          "WITH params AS (\r\n",
          "  SELECT\r\n",
          "    add_months(date_trunc('MONTH', current_date()), -13) AS start_month, -- 13 complete months window start\r\n",
          "    last_day(add_months(current_date(), -1)) AS end_date -- last day of previous month\r\n",
          "),\r\n",
          "-- Month spine: one row per month in the range\r\n",
          "months AS (\r\n",
          "  SELECT\r\n",
          "    explode(\r\n",
          "      sequence(\r\n",
          "        (\r\n",
          "          SELECT\r\n",
          "            start_month\r\n",
          "          FROM\r\n",
          "            params\r\n",
          "        ),\r\n",
          "        date_trunc(\r\n",
          "          'MONTH',\r\n",
          "          (\r\n",
          "            SELECT\r\n",
          "              end_date\r\n",
          "            FROM\r\n",
          "              params\r\n",
          "          )\r\n",
          "        ),\r\n",
          "        interval 1 month\r\n",
          "      )\r\n",
          "    ) AS month\r\n",
          "),\r\n",
          "-- Region spine: union of regions appearing in any source within timeframe\r\n",
          "regions AS (\r\n",
          "  SELECT DISTINCT\r\n",
          "    Region\r\n",
          "  FROM\r\n",
          "    main.bi_output.bi_output_vg_revenue\r\n",
          "  WHERE\r\n",
          "    Date BETWEEN\r\n",
          "      (\r\n",
          "        SELECT\r\n",
          "          start_month\r\n",
          "        FROM\r\n",
          "          params\r\n",
          "      )\r\n",
          "    AND\r\n",
          "      (\r\n",
          "        SELECT\r\n",
          "          end_date\r\n",
          "        FROM\r\n",
          "          params\r\n",
          "      )\r\n",
          "  UNION\r\n",
          "  SELECT DISTINCT\r\n",
          "    Region\r\n",
          "  FROM\r\n",
          "    main.bi_output.bi_output_vg_customer_snapshot\r\n",
          "  WHERE\r\n",
          "    IsLastDayMonth = 1\r\n",
          "    AND Date BETWEEN\r\n",
          "      (\r\n",
          "        SELECT\r\n",
          "          start_month\r\n",
          "        FROM\r\n",
          "          params\r\n",
          "      )\r\n",
          "    AND\r\n",
          "      (\r\n",
          "        SELECT\r\n",
          "          end_date\r\n",
          "        FROM\r\n",
          "          params\r\n",
          "      )\r\n",
          "  UNION\r\n",
          "  SELECT DISTINCT\r\n",
          "    Region\r\n",
          "  FROM\r\n",
          "    main.bi_output.bi_output_vg_customer_first_dates\r\n",
          "  WHERE\r\n",
          "    Global_FTD_Date IS NOT NULL\r\n",
          "    AND Global_FTD_Date BETWEEN\r\n",
          "      (\r\n",
          "        SELECT\r\n",
          "          start_month\r\n",
          "        FROM\r\n",
          "          params\r\n",
          "      )\r\n",
          "    AND\r\n",
          "      (\r\n",
          "        SELECT\r\n",
          "          end_date\r\n",
          "        FROM\r\n",
          "          params\r\n",
          "      )\r\n",
          "  UNION\r\n",
          "  SELECT DISTINCT\r\n",
          "    Region\r\n",
          "  FROM\r\n",
          "    main.bi_output.bi_output_vg_mimo\r\n",
          "  WHERE\r\n",
          "    Date BETWEEN\r\n",
          "      (\r\n",
          "        SELECT\r\n",
          "          start_month\r\n",
          "        FROM\r\n",
          "          params\r\n",
          "      )\r\n",
          "    AND\r\n",
          "      (\r\n",
          "        SELECT\r\n",
          "          end_date\r\n",
          "        FROM\r\n",
          "          params\r\n",
          "      )\r\n",
          "),\r\n",
          "spine AS (\r\n",
          "  SELECT\r\n",
          "    m.month,\r\n",
          "    r.Region\r\n",
          "  FROM\r\n",
          "    months m CROSS JOIN regions r\r\n",
          "),\r\n",
          "revenue_cte AS (\r\n",
          "  SELECT\r\n",
          "    date_trunc('MONTH', Date) AS month,\r\n",
          "    Region,\r\n",
          "    SUM(\r\n",
          "      CASE\r\n",
          "        WHEN IncludedInTotalRevenue = TRUE THEN Amount\r\n",
          "        ELSE 0\r\n",
          "      END\r\n",
          "    ) AS Revenue,\r\n",
          "    count(distinct case when iscopy=0 and IsSettled=0 then realcid end ) as ActiveOpenCFD,\r\n",
          "    count(distinct case when iscopy=0 and countasactiveTrade=1 then realcid end ) as ActiveCustomers\r\n",
          "  FROM\r\n",
          "    main.bi_output.bi_output_vg_revenue\r\n",
          "  WHERE\r\n",
          "    Date BETWEEN\r\n",
          "      (\r\n",
          "        SELECT\r\n",
          "          start_month\r\n",
          "        FROM\r\n",
          "          params\r\n",
          "      )\r\n",
          "    AND\r\n",
          "      (\r\n",
          "        SELECT\r\n",
          "          end_date\r\n",
          "        FROM\r\n",
          "          params\r\n",
          "      )\r\n",
          "  GROUP BY\r\n",
          "    date_trunc('MONTH', Date),\r\n",
          "    Region\r\n",
          "),\r\n",
          "funded_accounts_cte AS (\r\n",
          "  SELECT\r\n",
          "    date_trunc('MONTH', cs.Date) AS month,\r\n",
          "    cs.Region,\r\n",
          "    COUNT(DISTINCT\r\n",
          "      CASE\r\n",
          "        WHEN ds.IsFunded = 1 THEN cs.RealCID\r\n",
          "      END\r\n",
          "    ) AS FundedAccounts,\r\n",
          "    cast(sum(case when cs.playerlevelid<>1 then ds.isfunded end) as decimal(38,6)) as Club_Funded -- added by Adi\r\n",
          "  FROM\r\n",
          "    main.bi_output.bi_output_vg_customer_snapshot cs\r\n",
          "    JOIN main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_ddr_customer_daily_status ds\r\n",
          "      ON cs.RealCID = CAST(ds.RealCID AS STRING) AND cs.Date = ds.Date\r\n",
          "  WHERE\r\n",
          "    cs.IsLastDayMonth = 1\r\n",
          "    AND cs.Date BETWEEN\r\n",
          "      (\r\n",
          "        SELECT\r\n",
          "          start_month\r\n",
          "        FROM\r\n",
          "          params\r\n",
          "      )\r\n",
          "    AND\r\n",
          "      (\r\n",
          "        SELECT\r\n",
          "          end_date\r\n",
          "        FROM\r\n",
          "          params\r\n",
          "      )\r\n",
          "  GROUP BY\r\n",
          "    date_trunc('MONTH', cs.Date),\r\n",
          "    cs.Region\r\n",
          "),\r\n",
          "ftd_cte AS (\r\n",
          "  SELECT\r\n",
          "    date_trunc('MONTH', Global_FTD_Date) AS month,\r\n",
          "    Region,\r\n",
          "    COUNT(DISTINCT RealCID) AS FTDs\r\n",
          "  FROM\r\n",
          "    main.bi_output.bi_output_vg_customer_first_dates\r\n",
          "  WHERE\r\n",
          "    Global_FTD_Date IS NOT NULL\r\n",
          "    AND Global_FTD_Date BETWEEN\r\n",
          "      (\r\n",
          "        SELECT\r\n",
          "          start_month\r\n",
          "        FROM\r\n",
          "          params\r\n",
          "      )\r\n",
          "    AND\r\n",
          "      (\r\n",
          "        SELECT\r\n",
          "          end_date\r\n",
          "        FROM\r\n",
          "          params\r\n",
          "      )\r\n",
          "  GROUP BY\r\n",
          "    date_trunc('MONTH', Global_FTD_Date),\r\n",
          "    Region\r\n",
          "),\r\n",
          "deposits_cte AS (\r\n",
          "  SELECT\r\n",
          "    date_trunc('MONTH', Date) AS month,\r\n",
          "    Region,\r\n",
          "    SUM(GlobalDepositsAmount) AS Deposits,\r\n",
          "    sum(GlobalWithdrawsAmount) as Withdrawals\r\n",
          "  FROM\r\n",
          "    main.bi_output.bi_output_vg_mimo\r\n",
          "  WHERE\r\n",
          "    Date BETWEEN\r\n",
          "      (\r\n",
          "        SELECT\r\n",
          "          start_month\r\n",
          "        FROM\r\n",
          "          params\r\n",
          "      )\r\n",
          "    AND\r\n",
          "      (\r\n",
          "        SELECT\r\n",
          "          end_date\r\n",
          "        FROM\r\n",
          "          params\r\n",
          "      )\r\n",
          "  GROUP BY\r\n",
          "    date_trunc('MONTH', Date),\r\n",
          "    Region\r\n",
          "),\r\n",
          "-- Churn: client was funded last month (IsFunded=1) but not this month (IsFunded=0)\r\n",
          "churn_detail AS (\r\n",
          "  SELECT\r\n",
          "    date_trunc('MONTH', cs.Date) AS month,\r\n",
          "    cs.Region,\r\n",
          "    cs.RealCID,\r\n",
          "    ds.IsFunded,\r\n",
          "    LAG(ds.IsFunded) OVER (PARTITION BY cs.RealCID ORDER BY cs.Date) AS prev_IsFunded\r\n",
          "  FROM\r\n",
          "    main.bi_output.bi_output_vg_customer_snapshot cs\r\n",
          "    JOIN main.bi_db.gold_sql_dp_prod_we_bi_db_dbo_bi_db_ddr_customer_daily_status ds\r\n",
          "      ON cs.RealCID = CAST(ds.RealCID AS STRING) AND cs.Date = ds.Date\r\n",
          "  WHERE\r\n",
          "    cs.IsLastDayMonth = 1\r\n",
          "    AND cs.Date BETWEEN\r\n",
          "      add_months((SELECT start_month FROM params), -1)  -- 1 extra month back for LAG\r\n",
          "    AND\r\n",
          "      (SELECT end_date FROM params)\r\n",
          "),\r\n",
          "churn_cte AS (\r\n",
          "  SELECT\r\n",
          "    month,\r\n",
          "    Region,\r\n",
          "    COUNT(DISTINCT\r\n",
          "      CASE\r\n",
          "        WHEN IsFunded = 0 AND prev_IsFunded = 1 THEN RealCID\r\n",
          "      END\r\n",
          "    ) AS Churned\r\n",
          "  FROM\r\n",
          "    churn_detail\r\n",
          "  WHERE\r\n",
          "    month >= (SELECT start_month FROM params)  -- only report months in original range\r\n",
          "  GROUP BY\r\n",
          "    month,\r\n",
          "    Region\r\n",
          ")\r\n",
          "SELECT\r\n",
          "  s.month,\r\n",
          "  s.Region,\r\n",
          "  COALESCE(rv.Revenue, 0) AS Revenue,\r\n",
          "  COALESCE(fa.FundedAccounts, 0) AS FundedAccounts,\r\n",
          "  COALESCE(ft.FTDs, 0) AS FTDs,\r\n",
          "  COALESCE(dp.Deposits, 0) AS Deposits,\r\n",
          "  COALESCE(fa.Club_Funded, 0) AS Club_Funded, -- added by Adi\r\n",
          "  coalesce(dp.Deposits,0)-coalesce(dp.Withdrawals,0) as Net_Deposits, -- added by Adi\r\n",
          "  coalesce(rv.revenue,0)/coalesce(fa.fundedaccounts,0) as ARPU_Funded, -- added by Adi\r\n",
          "  COALESCE(ch.Churned, 0) AS Churned, -- churn indicator-- added by Adi\r\n",
          "  COALESCE(ch.Churned, 0)/COALESCE(fa.FundedAccounts, 0) as Churn_Rate,-- added by Adi\r\n",
          "  coalesce(rv.activecustomers,0) as Active_Customers,\r\n",
          "  coalesce(rv.activeopencfd,0) as Active_CFD_Users\r\n",
          "FROM\r\n",
          "  spine s\r\n",
          "    LEFT JOIN revenue_cte rv\r\n",
          "      ON s.month = rv.month\r\n",
          "      AND s.Region = rv.Region\r\n",
          "    LEFT JOIN funded_accounts_cte fa\r\n",
          "      ON s.month = fa.month\r\n",
          "      AND s.Region = fa.Region\r\n",
          "    LEFT JOIN ftd_cte ft\r\n",
          "      ON s.month = ft.month\r\n",
          "      AND s.Region = ft.Region\r\n",
          "    LEFT JOIN deposits_cte dp\r\n",
          "      ON s.month = dp.month\r\n",
          "      AND s.Region = dp.Region\r\n",
          "    LEFT JOIN churn_cte ch\r\n",
          "      ON s.month = ch.month\r\n",
          "      AND s.Region = ch.Region\r\n",
          "ORDER BY\r\n",
          "  s.month ASC,\r\n",
          "  s.Region ASC\r\n"
        ]
      }
    ],
