        "question": [
          "snapshot should have only joined on RealCID"
        ],
        "answer": [
          {
            "format": "SQL",
            "content": [
              "WITH revenue AS (\n",
              "  SELECT RealCID, CalendarYearMonth, Amount\n",
              "  FROM main.bi_output.bi_output_vg_revenue\n",
              "  WHERE IncludedInTotalRevenue = true\n",
              "),\n",
              "snapshot AS (\n",
              "  SELECT RealCID, CalendarYearMonth\n",
              "  FROM main.bi_output.bi_output_vg_customer_snapshot\n",
              "  WHERE IsFunded = 1 AND IsLastDayMonth = 1\n",
              ")\n",
              "SELECT r.CalendarYearMonth, SUM(r.Amount) AS total_revenue\n",
              "FROM revenue r\n",
              "JOIN snapshot s\n",
              "  ON r.RealCID = s.RealCID\n",
              "  AND r.CalendarYearMonth = s.CalendarYearMonth\n",
              "WHERE r.CalendarYearMonth >= date_format(date_add(current_date(), -365), 'yyyy-MM')\n",
              "GROUP BY r.CalendarYearMonth\n",
              "ORDER BY r.CalendarYearMonth"
            ]
          }
        ]
